import{_ as e,c as a,a as i,o as n}from"./app-CEcM0piI.js";const l={};function t(d,s){return n(),a("div",null,s[0]||(s[0]=[i(`<ul><li>请求行：请求数据第一行（请求方式、资源路径、协议）</li><li>请求头：从第二行开始，格式key：value</li><li>请求体 : POST请求，存放请求参数 请求行或每个请求头结尾都是<code>\\r\\n</code> 请求体和请求头之间有空行隔开他们之间的字符是<code>\\r\\n\\r\\n</code></li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>POST /brand HTTP/1.1</span></span>
<span class="line"><span>Accept:application/json,text/plain, */*</span></span>
<span class="line"><span>Accept-Encoding: gzip, deflate,br</span></span>
<span class="line"><span>Accept-Language: zh-CN,zh;q=0.9</span></span>
<span class="line"><span>Content-Length: 161</span></span>
<span class="line"><span>Content-Type: application/json;charset=UTF-8</span></span>
<span class="line"><span>Cookie: Idea-8296eb32=841b16f0-0cfe-495a-9cc9-d5aaa71501a6;JSESSI0NID=0FDE4E430876BD9C5C955F061207386F</span></span>
<span class="line"><span>Host: 1ocalhost:8080</span></span>
<span class="line"><span>User-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/..</span></span>
<span class="line"><span></span></span>
<span class="line"><span>{&quot;status&quot;:1,&quot;brandName&quot;:&quot;黑马&quot;,&quot;companyName&quot;:&quot;黑马程序员&quot;,&quot;id&quot;:&quot;&quot;,&quot;description&quot;：&quot;黑马程序员&quot;}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><table><thead><tr><th>常见请求头</th><th>作用</th></tr></thead><tbody><tr><td>Host</td><td>请求的主机名</td></tr><tr><td>User-Agent</td><td>浏览器版本，例如Chrome浏览器的标识类似Mozilla/5.0 ...Chrome/79，IE浏览器的标识类似Mozilla/5.(WindowsNT ...) like Gecko</td></tr><tr><td>Accept</td><td>表示浏览器能接收的资源类型，如text/*，image/*或者*/*表示所有;</td></tr><tr><td>Accept-Language</td><td>表示浏览器偏好的语言，服务器可以据此返回不同语言的网页；</td></tr><tr><td>Accept-Encoding</td><td>表示浏览器可以支持的压缩类型，例如gzip，deflate等。</td></tr><tr><td>Content-Type</td><td>请求主体的数据类型。</td></tr><tr><td>Content-Length</td><td>请求主体的大小（单位：字节）。</td></tr></tbody></table><ul><li>请求方式-GET：请求参数在请求行中，没有请求体，如：/brand/findAll?name=OPPO&amp;status=1。GET请求大小是有限制的。</li><li>请求方式-POST：请求参数在请求体中，POST请求大小是没有限制的。 浏览器地址栏发送到请求全部都是get请求</li></ul><p>Spring 有两个最核心模块：loC 和 AOP。</p><ol><li>loC：Inverse of Control的简写，译为&quot;控制反转&quot;，指把创建对象过程交给Spring 进行管理。</li><li>AoP：Aspect Oriented Programming 的简写，译为&quot;面向切面编程&quot;。AOP 用来封装多个类的公共行为，将那些与业务无关，却为业务模块所共同调用的逻辑封装起来，减少系统的重复代码，降低模块间的耦合度。另外，AOP还解决一些系统层面上的问题，比如日志、事务、权限等。</li></ol><p>spring项目进行打包时，需要引入插件（基于官网骨架创建项目，会自动添加该插件）</p><p>配置的优先级: 命令行参数&gt;java系统属性&gt;.properties&gt;.yml&gt;.yaml</p><h1 id="rest" tabindex="-1"><a class="header-anchor" href="#rest"><span>REST</span></a></h1><p>（Representational State Transfer），表现形式状态转换 通俗来讲就是网络风格资源描述形式</p><ul><li>传统风格资源描述形式</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>http://localhost/user/getById?id=1</span></span>
<span class="line"><span>http://localhost/user/saveUser</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>REST风格描述形式</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>http://localhost/user/1</span></span>
<span class="line"><span>http://localhost/user</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>优点：</p><ol><li>隐藏资源的访问行为，无法通过地址得知对资源是何种操作</li><li>书写简化</li></ol><p>这也使有的访问资源的行为使用了同样的描述 要区分访问资源的行为可以通过请求的方法来区分</p><p>按照REST风格访问资源时使用行为动作区分对资源进行了何种操作</p><table><thead><tr><th>url</th><th>行为</th><th>请求</th></tr></thead><tbody><tr><td>http://localhost/users</td><td>查询全部用户信息</td><td>GET (查询)</td></tr><tr><td>http://localhost/users/1</td><td>查询指定用户信息</td><td>GET (查询)</td></tr><tr><td>http://localhost/users</td><td>添加用户信息</td><td>POST (新增/保存)</td></tr><tr><td>http://localhost/users</td><td>修改用户信息</td><td>PUT (修改/更新)</td></tr><tr><td>http://localhost/users/1</td><td>删除用户信息</td><td>DELETE (删除)</td></tr><tr><td>上述行为是约定方式，约定不是规范，可以打破，所以称REST风格，而不是REST规范</td><td></td><td></td></tr><tr><td>描述模块的名称通常使用复数，也就是加s的格式描述，表示此类资源，而非单个资源，例如：users、books、accounts.</td><td></td><td></td></tr></tbody></table><p><strong>根据REST风格对资源进行访问称为RESTful</strong></p><p>在springboot中使用RESTful的方法是在路由上对指定路径的资源访问方式做限制</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@RequestMapping(value=&quot;/users&quot;,method=RequestMethod.POST)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="设定请求参数-路径变量" tabindex="-1"><a class="header-anchor" href="#设定请求参数-路径变量"><span>设定请求参数(路径变量)</span></a></h4><p>在形参列表中对指定的参数设置@PathVariable注解可以让该形参作为变量,在@RequestMapping中使用大括号的方法对该形参名可以取值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@RequestMapping(value = &quot;/users/{id}&quot;,method = RequestMethod.DELETE)</span></span>
<span class="line"><span>@ResponseBody</span></span>
<span class="line"><span>public String delete(@PathVariable Integer id){</span></span>
<span class="line"><span>	System.out.println(&quot;user delete...&quot; + id);</span></span>
<span class="line"><span>	returnn &quot;{&#39;module&#39;:&#39;user delete&#39;}&quot;;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>@RequestParam用于接收url地址传参或表单传参</li><li>@RequestBody用于接收json数据</li><li>@PathVariable用于接收路径参数，使用{参数名称}描述路径参数</li></ul><h3 id="rest快速开发" tabindex="-1"><a class="header-anchor" href="#rest快速开发"><span>REST快速开发</span></a></h3><h4 id="restcontroller" tabindex="-1"><a class="header-anchor" href="#restcontroller"><span>@RestController</span></a></h4><p>基于SpringMVc的RESTful开发控制器类定义上方 设置当前控制器类为RESTful风格，等同于@Controller与@ResponseBody两个注解组合功能</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@RestController</span></span>
<span class="line"><span>public class BookController{</span></span>
<span class="line"><span></span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="getmapping-postmapping-putmapping-deletemapping" tabindex="-1"><a class="header-anchor" href="#getmapping-postmapping-putmapping-deletemapping"><span>@GetMapping @PostMapping @PutMapping @DeleteMapping</span></a></h4><p>基于SpringMVc的RESTful开发控制器方法定义上方 设置当前控制器方法请求访问路径与请求动作，每种对应下个请求动作，例如@GetMapping对应GET请求</p><ul><li>value（默认）：请求访问路径</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@GetMapping(&quot;/{id}&quot;)</span></span>
<span class="line"><span>public String getById(@PathVariable Integer id){</span></span>
<span class="line"><span>	System.out.println(&quot;book getById...&quot;+id);</span></span>
<span class="line"><span>	return&quot;{&#39;module&#39;:&#39;book getById&#39;}&quot;;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="配置文件" tabindex="-1"><a class="header-anchor" href="#配置文件"><span>配置文件</span></a></h1><p>springboot的配置文件名必须为application,后缀名可以是properties,yml,ymal 如果三个格式同时存在 有冲突的属性默认使用properties文件,其次是yml最后是yaml 没有冲突的属性全都保留(取并集)</p><h3 id="读取配置信息" tabindex="-1"><a class="header-anchor" href="#读取配置信息"><span>读取配置信息</span></a></h3><h4 id="读取单个信息" tabindex="-1"><a class="header-anchor" href="#读取单个信息"><span>读取单个信息</span></a></h4><p>使用@Value注解</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Value(&quot;\${name})</span></span>
<span class="line"><span>private String name1;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@Value(&quot;\${user.name}&quot;)</span></span>
<span class="line"><span>private String name2;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这样就可以把name1赋值为配置文件里的name的值了 获取指定键下的键的值使用.分层 如果是数组使用方括号根据索引取值</p><h4 id="读取全部的配置信息" tabindex="-1"><a class="header-anchor" href="#读取全部的配置信息"><span>读取全部的配置信息</span></a></h4><p>一个一个获取变量很不方便可以使用自动装配配置到一个环境中,使用spring提供的Environment类接收</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Autowried</span></span>
<span class="line"><span>private Environment env;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>使用getProperty函数根据传入的键获取Environment中对应的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>env.getProperty(&quot;user.name&quot;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="读取部分信息" tabindex="-1"><a class="header-anchor" href="#读取部分信息"><span>读取部分信息</span></a></h4><p>但很多时候一个类并不需要所有的配置,只需要一部分配置,这时就需要读取部分信息 需要先设置一个类 在类上面加上@Component注解是spring能够管控这个类 在类上面加上@configurationProperties注解其中的profix指定配置文件的键用于根据键获取对应的值 在使用的时候在该类的实例上添加Autowired自动装配</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>// datasource:</span></span>
<span class="line"><span>//     driver:com.mysql.jdbc.Driver</span></span>
<span class="line"><span>//     url:jdbc:mysql://localhost/springboot_db</span></span>
<span class="line"><span>//     username:root</span></span>
<span class="line"><span>//     password:root666123</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@Component</span></span>
<span class="line"><span>@configurationProperties(profix=&quot;datasource&quot;)</span></span>
<span class="line"><span>public class MyDtatSource{</span></span>
<span class="line"><span>	private String driver;</span></span>
<span class="line"><span>	private String url;</span></span>
<span class="line"><span>	private String username;</span></span>
<span class="line"><span>	private String password;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>@Autowired</span></span>
<span class="line"><span>private MyDataSource myDataSource;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>SpringBoot除了支持配置文件属性配置，还支持Java系统属性和命令行参数的方式进行属性配置。</p><h3 id="java系统属性" tabindex="-1"><a class="header-anchor" href="#java系统属性"><span>java系统属性</span></a></h3><p>前面加一个横杠</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>-Dserver.port=9000</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="命令行参数" tabindex="-1"><a class="header-anchor" href="#命令行参数"><span>命令行参数</span></a></h3><p>前面要加两个横杠</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>--server.port=10010</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="获取配置信息" tabindex="-1"><a class="header-anchor" href="#获取配置信息"><span>获取配置信息</span></a></h1><h3 id="value" tabindex="-1"><a class="header-anchor" href="#value"><span>@Value</span></a></h3><p>通过</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Value(&quot;\${键名}&quot;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>获取键名中的值,不同层级需要使用.指明</p><p>如:获取server中port的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Value(&quot;server.port&quot;)</span></span>
<span class="line"><span>public string port;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="configurationproperties" tabindex="-1"><a class="header-anchor" href="#configurationproperties"><span>@ConfigurationProperties</span></a></h3><p>使用这个注解可以获取一个前缀中的所有键值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@ConfigurationProperties(prefix=&quot;server&quot;)</span></span>
<span class="line"><span>public class Test{</span></span>
<span class="line"><span>	public string port;</span></span>
<span class="line"><span>};</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>\\</p><h3 id="第三方依赖提示" tabindex="-1"><a class="header-anchor" href="#第三方依赖提示"><span>第三方依赖提示</span></a></h3><p>如果有引入第三方依赖的配置,在配置文件中可能不会有提示,可以引入springboot-configuration-process依赖,引入此依赖后在配置第三方配置时就会有提示了,且使用注入获取配置信息也不会爆红了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>		&lt;dependency&gt;</span></span>
<span class="line"><span>			&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;</span></span>
<span class="line"><span>			&lt;artifactId&gt;spring-boot-configuration-processor&lt;/artifactId&gt;</span></span>
<span class="line"><span>		&lt;/dependency&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但有时候提示的配置拼写是横杠分隔的,而传统的配置是驼峰命名的这也没关系,两种方法都能使用</p><h1 id="beans-xml" tabindex="-1"><a class="header-anchor" href="#beans-xml"><span>beans.xml</span></a></h1><div class="language-beans.xml line-numbers-mode" data-highlighter="shiki" data-ext="beans.xml" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;</span></span>
<span class="line"><span>&lt;beans xmlns=&quot;http://www.springframework.org/schema/beans&quot;</span></span>
<span class="line"><span>	xmlns:xsi=&quot;http://www.w3.org/2001/XMLSchema-instance&quot;</span></span>
<span class="line"><span>	xsi:schemaLocation=&quot;http://www.springframework.org/schema/beans</span></span>
<span class="line"><span>	http://www.springframework.org/schema/beans/spring-beans-3.0.xsd&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	&lt;bean id=&quot;user&quot; class=&quot;com.example.spring6.User&quot;&gt;&lt;/bean&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;/beans&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="bean标签" tabindex="-1"><a class="header-anchor" href="#bean标签"><span>bean标签</span></a></h3><ul><li>id属性：唯一标识</li><li>class属性：要创建对象所在类的全路径（包名称+类名称）</li></ul><h1 id="使用spring的方法创建对象" tabindex="-1"><a class="header-anchor" href="#使用spring的方法创建对象"><span>使用spring的方法创建对象</span></a></h1><p>传入配置文件的路径加载配置文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>ApplicationContext context = new ClassPathXmlApplicationContext(&quot;beans.xml&quot;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>获取创建的对象 根据配置文件中的bean的id获取对应的对象</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>User user = (User)context.getBean(&quot;user&quot;);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用spring 的方法创建对象不用new 的方式,底层是使用反射创建的</p><h1 id="自动配置" tabindex="-1"><a class="header-anchor" href="#自动配置"><span>自动配置</span></a></h1><p>SpringBoot的自动配置就是当spring容器启动后，一些配置类、bean对象就自动存入到了lOc容器中，不需要我们手动去声明，从而简化了开发，省去了繁琐的配置操作。</p><h2 id="组件扫描" tabindex="-1"><a class="header-anchor" href="#组件扫描"><span>组件扫描</span></a></h2><p>当spring启动时会进行扫描扫描启动类所在包及子包,当有被@Componect及其衍生注解修饰的类时就会注册为bean对象加入到ioc容器中由spring管理 如果有包不在被扫描的范围内,可以使用@Componentscan指定要扫描的包,被扫描的包及其子包也会被扫描</p><h3 id="conditional" tabindex="-1"><a class="header-anchor" href="#conditional"><span>@Conditional</span></a></h3><p>作用：按照一定的条件进行判断，在满足给定条件后才会注册对应的bean对象到SpringIOc容器中。 位置：方法、类 声明在类上表示对整个类都有效 声明在方法上(要与@Bean配合使用)表示只对当前方法声明的bean有效</p><p>@Conditional本身是一个父注解，派生出大量的子注解：</p><ul><li>@ConditionalOnClass：判断环境中是否有对应字节码文件，才注册bean到ioc容器。</li><li>@ConditionalOnMissingBean：判断环境中没有对应的bean（类型或名称），才注册bean到loc容器。如果要根据指定的类型判断需要使用value属性指定,如果要根据指定的名称判读需要使用name属性指定</li><li>@ConditionalOnProperty：判断配置文件中有对应属性和值，才注册bean到loc容器。name属性用于指定属性名,havingValue属性用于指定属性名对应的值</li></ul><h2 id="起步依赖" tabindex="-1"><a class="header-anchor" href="#起步依赖"><span>起步依赖</span></a></h2><p>在实际开发中，经常会定义一些公共组件，提供给各个项目团队使用。而在SpringBoot的项目中，一般会将这些公共组件封装为SpringBoot 的 starter。</p><p>一般来说springboot整合的起步依赖都是 : spring-boot-starter-名称 第三方主动适配spring的起步以来都是 : 名称-spring-boot-starter</p><h1 id="引导类" tabindex="-1"><a class="header-anchor" href="#引导类"><span>引导类</span></a></h1><p>SpringBoot的引l导类是Boot工程的执行入口，运行main方法就可以启动项目 SpringBoot工程运行后初始化Spring容器，扫描引导类所在包加载bean</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@SpringBootApplication</span></span>
<span class="line"><span>public class QuickstartApplication {</span></span>
<span class="line"><span>	public static void main(String[] args) {</span></span>
<span class="line"><span>		SpringApplication.run(QuickstartApplication.class, args);</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>返回的是spring的ioc容器,可以使用getBean获取其中加载的bean对象</p><h1 id="配置" tabindex="-1"><a class="header-anchor" href="#配置"><span>配置</span></a></h1><h2 id="使用传统的spring配置文件" tabindex="-1"><a class="header-anchor" href="#使用传统的spring配置文件"><span>使用传统的spring配置文件</span></a></h2><h2 id="使用注解" tabindex="-1"><a class="header-anchor" href="#使用注解"><span>使用注解</span></a></h2><h2 id="基于配置文件项目配置的注解" tabindex="-1"><a class="header-anchor" href="#基于配置文件项目配置的注解"><span>基于配置文件项目配置的注解</span></a></h2><p>如果要接手一个项目,这个项目是使用xml文件配置的,若想要使用注解开发可以在配置类上添加一个@ImportResource导入对应的配置</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@ImportResource(&quot;application.xml&quot;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>@Import(MyImportSelector.class)</span></span>
<span class="line"><span>public class SpringConfig {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  @Bean</span></span>
<span class="line"><span>  //@ConditionalOnClass(Mouse.class)//当发现有一个老鼠就创建一个猫类</span></span>
<span class="line"><span>  //@ConditionalOnMissingClass(&quot;com.itheima.bean.Mouse&quot;)//当没有这个类的话就创建一个猫类</span></span>
<span class="line"><span>  @ConditionalOnBean(name=&quot;jerry&quot;)//只有名为jerry的bean存在时才创建一个猫类</span></span>
<span class="line"><span>  public Cat tom(){</span></span>
<span class="line"><span>    return new Cat();</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,103)]))}const r=e(l,[["render",t]]),c=JSON.parse('{"path":"/back/springboot/1/","title":"1 概述","lang":"zh-CN","frontmatter":{"title":"1 概述","createTime":"2025/04/05 12:12:26","permalink":"/back/springboot/1/"},"readingTime":{"minutes":9.07,"words":2721},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/Spring Boot/1 概述.md","headers":[]}');export{r as comp,c as data};
